+export const $aspect = Symbol('koota.aspect');
+
+export type Aspect<T extends readonly (Trait | Aspect)[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: readonly Trait[];
+    readonly schema: Record<string, unknown>;
+    readonly [$aspect]: true;
+};
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends readonly (Trait | Aspect)[]>(...inputs: T): Aspect<T> {
+    if (inputs.length < 2) throw new Error('Koota: createAspect requires at least two traits.');
+    const traits = inputs.flatMap((input) => isAspect(input) ? input.traits : [input]);
+    const schema: Record<string, unknown> = {};
+    const fields = new Set<string>();
+    for (const trait of traits) {
+        if (isRelation(trait as never) || trait[$internal].relation) {
+            throw new Error('Koota: relations cannot be aspect constituents.');
+        }
+        for (const field of Object.keys(trait.schema as Schema)) {
+            if (fields.has(field)) throw new Error(`Koota: aspect field "${field}" overlaps.`);
+            fields.add(field);
+            schema[field] = (trait.schema as Record<string, unknown>)[field];
+        }
+    }
+    return Object.freeze({ id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze(schema), [$aspect]: true }) as Aspect<T>;
+}
+
+export function hasAspect(entity: Entity, aspect: Aspect): boolean {
+    const world = getEntityWorld(entity);
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(entity: Entity, aspect: Aspect): Record<string, unknown> | undefined {
+    if (!hasAspect(entity, aspect)) return undefined;
+    const world = getEntityWorld(entity);
+    return Object.assign({}, ...aspect.traits.map((trait) => getTrait(world, entity, trait)));
+}
+
+function valuesFor(aspect: Aspect, value: Record<string, unknown>) {
+    return aspect.traits.map((trait) => {
+        const fields: Record<string, unknown> = {};
+        for (const key of Object.keys(trait.schema)) if (key in value) fields[key] = value[key];
+        return fields;
+    });
+}
+
+export function setAspect(entity: Entity, aspect: Aspect, value: Record<string, unknown>) {
+    const world = getEntityWorld(entity);
+    aspect.traits.forEach((trait, index) => setTrait(world, entity, trait, valuesFor(aspect, value)[index], true));
+}
+
+export function addAspect(entity: Entity, aspect: Aspect, value: Record<string, unknown> = {}) {
+    const world = getEntityWorld(entity);
+    const values = valuesFor(aspect, value);
+    aspect.traits.forEach((trait, index) => {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, values[index] as TraitValue<any>]);
+    });
+}
+
+export function removeAspect(entity: Entity, aspect: Aspect) {
+    removeTrait(getEntityWorld(entity), entity, ...aspect.traits);
+}
